import hashlib
import hmac
import base64
from secrets import token_urlsafe
from time import time
from pyqrcode import create

class TOTP:
    def __init__(self, secret):
        self.secret = secret
    
    @property
    def secret(self):
        return self._secret
    
    @secret.setter
    def secret(self, value):
        if not isinstance(value, str):
            raise ValueError("Secret must be a string")
        self._secret = value
    
    @staticmethod
    def generate_secret():
        return token_urlsafe(32)
    
    def generate_qrcode(self, name, email):
        qrcode = create(name=name, email=email, secret=self.secret)
        return qrcode
    
    def verify_otp(self, otp):
        if not isinstance(otp, str):
            raise ValueError("OTP must be a string")
        try:
            int(otp)
        except ValueError:
            return False
        else:
            expected_otp = self.calculate_otp()
            return expected_otp == otp
    
    def calculate_otp(self):
        ts = time() // 30
        message = f"{ts}{self.secret}"
        hashed_message = hmac.new(str.encode(self.secret), str.encode(message), digestmod=hashlib.sha1).digest()
        otp = base64.b64encode(hashed_message).decode("utf-8")[:6]
        return otp